import{_ as e,o,c as i,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"23. Doctor Responsibilities","description":"","frontmatter":{"title":"23. Doctor Responsibilities","eba":"Doctors in Training 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/23-doctor-responsibilities.md","filePath":"ebas/doctors-in-training/doctor-employment/23-doctor-responsibilities.md"}'),s={name:"ebas/doctors-in-training/doctor-employment/23-doctor-responsibilities.md"};function n(a,t,c,l,p,d){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="_23-doctor-responsibilities" tabindex="-1">23. Doctor Responsibilities <a class="header-anchor" href="#_23-doctor-responsibilities" aria-label="Permalink to &quot;23. Doctor Responsibilities&quot;">​</a></h1><p><strong>23.1</strong> The Doctor provides medical services, including the keeping and maintaining of adequate medical records for Health Service patients.</p><p><strong>23.2</strong> The Doctor’s Duty Hours must be devoted to the duties of their appointment.</p><p><strong>23.3</strong> The Doctor must not, without the consent of the patient, divulge to any person any information acquired when attending to a patient except as follows:</p><p><strong>(a)</strong> to the Health Service’s Director of Medical Services, nursing staff or other medical staff where necessary to enable the Doctor to prescribe or act for that patient; or</p><p><strong>(b)</strong> for medico legal purposes, to disclose any information to the Health Service relating to the mental or physical condition of a Health Service patient or former patient.</p><p><strong>23.4</strong> The Doctor should ensure that work performed outside of their employing Health Service does not result in an overall or unsafe work pattern for that Doctor pursuant to subclause 35.3.</p><p><strong>23.5</strong> The Doctor will ensure that to the extent that it is practicable to do so time sheets (or equivalent) reflecting time worked (including any overtime) are submitted within the timeframe required by the Health Service.</p><p>Plain language terms: responsibilities.</p>',9)])])}const u=e(s,[["render",n]]);export{m as __pageData,u as default};
